INSERT INTO quotes (id, movie_id, text, character) VALUES
  (1, 11, 'They''ve shut down the main reactor.', 'Threepio'),
  (2, 11, 'We intercepted no transmissions.', 'Rebel Officer'),
  (3, 11, 'It must have been short- circuited.', 'Captain'),
  (4, 11, 'Signed aboard The Rand Ecliptic last week.', 'Biggs'),
  (5, 11, 'Believe me Luke, this planet is a big hunk of nothing...', 'Fixer'),
  (6, 11, 'If word of this gets out, it could generate sympathy for the Rebellion in the senate.', 'Commander'),
  (7, 11, 'How did I get into this mess?', 'Threepio'),
  (8, 11, 'He tricked me into going this way, but he''ll do no better.', 'Threepio'),
  (9, 11, 'Well, things haven''t been the same since you left, Biggs.', 'Luke'),
  (10, 11, 'Luke, I''m not going to wait for the Empire to draft me into service.', 'Biggs'),
  (11, 11, 'it won''t be long before your uncle is merely a tenant, slaving for the greater glory of the Empire.', 'Biggs'),
  (12, 11, 'I have no need for a protocol droid.', 'Owen'),
  (13, 11, 'Well, come on, Red, let''s go.', 'Luke'),
  (14, 11, 'I''m never gonna get out of here!', 'Luke'),
  (15, 11, 'You know of the Rebellion against the Empire?', 'Luke'),
  (16, 11, 'A person of some importance, sir -- I believe.', 'Threepio'),
  (17, 11, 'He''s kind of a strange old hermit.', 'Luke'),
  (18, 11, 'No, I don''t think he likes you at all.', 'Threepio'),
  (19, 11, 'But what if this Obi-Wan comes looking for him?', 'Luke'),
  (20, 11, 'You must understand I need you here, Luke.', 'Owen'),
  (21, 11, 'What are you doing hiding there?', 'Luke'),
  (22, 11, 'You know that little droid is going to cause me a lot of trouble.', 'Luke'),
  (23, 11, 'Wait, there''s something dead ahead on the scanner.', 'Luke'),
  (24, 11, 'Come on, let''s have a look.', 'Luke'),
  (25, 11, 'there seems to be no stopping him.', 'Luke'),
  (26, 11, 'The Sandpeople are easily startled but they will soon be back and in greater numbers.', 'Ben'),
  (27, 11, 'Yes, I was once a Jedi Knight the same as your father.', 'Ben'),
  (28, 11, 'Before the dark times, before the Empire.', 'Ben'),
  (29, 11, 'Now he begs you to help him in his struggle against the Empire.', 'Leia'),
  (30, 11, 'It''s such a long way from here.', 'Luke'),
  (31, 11, 'The Imperial Senate will no longer be of any concern to us.', 'Tarkin'),
  (32, 11, 'Don''t be too proud of this technological terror you''ve constructed.', 'Vader'),
  (33, 11, 'These tracks are side by side.', 'Ben'),
  (34, 11, 'I want to learn the ways of the Force and become a Jedi like my father.', 'Luke'),
  (35, 11, 'I can''t abide these Jawas.', 'Threepio'),
  (36, 11, 'I have the death sentence in twelve systems.', 'Human'),
  (37, 11, 'Myself, the boy, two droids, and no questions asked.', 'Ben'),
  (38, 11, 'We''ll leave as soon as you''re ready.', 'Han'),
  (39, 11, 'Yeah, but this time I got the money.', 'Han'),
  (40, 11, 'All systems are operational.', 'Imperial Officer'),
  (41, 11, 'I''ve been waiting for you, Jabba.', 'Han'),
  (42, 11, 'If only you hadn''t had to dump that shipment of spice...', 'Jabba'),
  (43, 11, 'I''ve added some special modifications myself.', 'Han'),
  (44, 11, 'Here''s where the fun begins!', 'Han'),
  (45, 11, 'I surprised you had the courage to take the responsibility yourself!', 'Leia'),
  (46, 11, 'Continue with the operation.', 'Tarkin'),
  (47, 11, 'It''s not wise to upset a Wookiee.', 'Han'),
  (48, 11, 'There''s no mystical energy field that controls my destiny.', 'Han'),
  (49, 11, 'I could almost see the remote.', 'Luke'),
  (50, 11, 'Thats what I''m trying to tell you, kid.', 'Han'),
  (51, 11, 'It''s too far out of range.', 'Ben'),
  (52, 11, 'But there''s gotta be something you can do!', 'Luke'),
  (53, 11, 'Several of the escape pods have been jettisoned.', 'Officer'),
  (54, 11, 'the fool or the fool who follows him?', 'Ben'),
  (55, 11, 'The tractor beam is coupled to the main reactor in seven locations.', 'Threepio'),
  (56, 11, 'He says "I found her", and keeps repeating, "She''s here.', 'Threepio'),
  (57, 11, 'Now all you want to do is stay.', 'Luke'),
  (58, 11, 'I can''t see a thing in this helmet.', 'Luke'),
  (59, 11, 'We had a reactor leak here now.', 'Han'),
  (60, 11, 'Put all sections on alert!', 'Tarkin'),
  (61, 11, 'Somebody has to save our skins.', 'Leia'),
  (62, 11, 'Something just moves past my leg!', 'Luke'),
  (63, 11, 'Thank goodness, they haven''t found them!', 'Threepio'),
  (64, 11, 'I take orders from one person!', 'Han'),
  (65, 11, 'That oughta hold it for a while.', 'Luke'),
  (66, 11, 'Seems okay, if we can get to it.', 'Han'),
  (67, 11, 'They have just made the jump into hyperspace.', 'Vader'),
  (68, 11, 'You needn''t worry about your reward.', 'Leia'),
  (69, 11, 'You must use the information in this R2 unit to plan the attack.', 'Leia'),
  (70, 11, 'A precise hit will start a chain reaction which should destroy the station.', 'Dodonna'),
  (71, 11, 'I got some old debts I''ve got to pay off with this stuff.', 'Han'),
  (72, 11, 'I don''t know, I really thought he''d change his mind.', 'Luke'),
  (73, 11, 'I told you I''d make it someday, Biggs.', 'Luke'),
  (74, 11, 'Look at the size of that thing!', 'Wedge'),
  (75, 11, 'Luke, let me know when you''re going in.', 'Red Leader'),
  (76, 11, 'We''re starting out attack run.', 'Gold Leader'),
  (77, 11, 'In out moment of triumph?', 'Tarkin'),
  (78, 11, 'Red Five, can you see them from where you are?', 'Red Ten''S Voice'),
  (79, 11, 'It''ll be just like Beggar''s Canyon back home.', 'Luke'),
  (80, 11, 'Rebel base, thirty seconds and closing.', 'Death Star Intercom Voice'),
  (81, 62, 'EXT cave AND PLAINS - Utopia', 'A12'),
  (82, 62, 'Please, it really doesn''t matter.', 'Floyd'),
  (83, 62, 'When you see the red light go on would you please state in the following order; your desitination, your nationality and your full name.', 'Passport Girl'),
  (84, 62, 'Your connecting flight will be leaving in about one hour.', 'Miller'),
  (85, 62, 'Oh, look, I''ve got to make a phone call.', 'Floyd'),
  (86, 62, 'I''m having a party tomorrow.', 'Child'),
  (87, 62, 'Mommy''s out to the hair- dresser.', 'Child'),
  (88, 62, 'I''ll wish you a happy Birthday now and I''ll see you soon.', 'Floyd'),
  (89, 62, 'Here is a lovely assortment of African bush babies.', 'Vision Sales Girl'),
  (90, 62, 'Please deliver to Miss Josephine Floyd, 9423 Dupre Avenue,', 'Floyd'),
  (91, 62, 'I''d like you to meet Andre Smyslov...', 'Elena'),
  (92, 62, 'If it''s all right I''ll just sit for a minute and then I''ve got to be off.', 'Floyd'),
  (93, 62, 'Oh, that''s such a delightful age.', 'Elena'),
  (94, 62, 'Well, as it happens, I''m on my way up to the moon', 'Floyd'),
  (95, 62, 'I''m sorry, but I''m not sure I know what you mean.', 'Floyd'),
  (96, 62, 'Another thing, Heywood, two days ago, one of our rocket buses was denied permission for an emergency landing at Clavius.', 'Elena'),
  (97, 62, 'Denying the men permission to land was a direct violation of the I.A.S.', 'Smyslov'),
  (98, 62, 'Something, apperently, of an unknown origin.', 'Smyslov'),
  (99, 62, 'I''m not permitted to discuss this.', 'Floyd'),
  (100, 62, 'It''s been a great pleasure to meet all of you...', 'Floyd'),
  (101, 62, 'Well, how''s it going back there?', 'Pilot'),
  (102, 62, 'Well, I''ve heard more and more people talk of an epidemic.', 'Co-Pilot'),
  (103, 62, 'I was working out what this trip must cost, taking him up there by himself and coming back empty.', 'Co-Pilot'),
  (104, 62, 'Did you have a good rest?', 'Pilot'),
  (105, 62, 'The two girls have taken wonderful care of me.', 'Floyd'),
  (106, 62, 'And then we''re going to back empty.', 'Pilot'),
  (107, 62, 'I wouldn''t think there''s any cause for alarm.', 'Floyd'),
  (108, 62, 'Well, thank you very much, and please let us know if there is anything we can do to make your trip more comfortable.', 'Pilot'),
  (109, 62, 'They no longer thought of Earth as home.', 'Narrator'),
  (110, 62, 'Heywood Floyd, a distinguished member of the National Council of Astronautics.', 'Halvorsen'),
  (111, 62, 'And of course you know that the Council has requested that formal security oaths are to be obtained in writing from every- one who had any knowledge of this event.', 'Floyd'),
  (112, 62, 'The sub-surface structure shows that it was deliberately buried about four million years ago.', 'Michaels'),
  (113, 62, 'The surface is made of something incredibly hard and we''ve been barely able to scratch it.', 'Michaels'),
  (114, 62, 'Was it abandoned, forgotten, left for a purpose?', 'Floyd'),
  (115, 62, 'Has it been exposed to any sun before now?', 'Floyd'),
  (116, 62, 'I see here that special lighting equipment had to be brought up before any futher work could be done.', 'Simpson'),
  (117, 62, 'Halvorsen on the other....', 'Photographer'),
  (118, 62, 'Well, it''s nothing really important, but it''s annoying.', 'Poole'),
  (119, 62, 'I assumed they''d start paying me at the higher grade on the next pay cheque.', 'Poole'),
  (120, 62, 'Well, what do you think we ought to do about it?', 'Poole'),
  (121, 62, 'I suppose the idea was specialized training.', 'Bowman'),
  (122, 62, 'That seems very unlikely.', 'Bowman'),
  (123, 62, 'Something that the rest of the crew know and that you know.', 'Poole'),
  (124, 62, 'It didn''t really make any sense to keep us apart during training.', 'Poole'),
  (125, 62, 'Still, all we have to do is ask Hal.', 'Poole'),
  (126, 62, 'At the end of a hundred days of exploration, we will all go into hibernation.', 'Poole'),
  (127, 62, 'Bowman and Poole settled down to the peaeful monotony of the voyage, and the next three months passed without incident.', 'Narrator'),
  (128, 62, 'shows an impending failure of the antenna orientation unit.', 'Hal'),
  (129, 62, 'unit should go so quickly.', 'Poole'),
  (130, 62, 'Hal, I''m going out now to replace the A.O.', 'Poole'),
  (131, 62, 'Hal, please acknowledge component correctly installed and fully operational.', 'Poole'),
  (132, 62, 'I suppose computers have been known to be wrong.', 'Bowman'),
  (133, 62, 'Gee, that''s strange, Hal.', 'Poole'),
  (134, 62, 'No, it''s working fine right now, but it''s going to go within seventy- two hours.', 'Hal'),
  (135, 62, 'Oh, I''m fine, I''m wide awake.', 'Bowman'),
  (136, 62, 'Well, I hope there''s nothing wrong with the assembly on those.', 'Bowman'),
  (137, 62, 'but it could also be any number of reasons.', 'Mission Control'),
  (138, 62, 'Well, that''s just not the case, Hal.', 'Bowman'),
  (139, 62, 'Hal, is there anything bothering you?', 'Bowman'),
  (140, 62, 'I know all about your service record, Hal, but unfortunately it doesn''t prove that you''re right now.', 'Bowman'),
  (141, 62, 'The computer has just reported another predicted failure off the AAC- unit.', 'Bowman'),
  (142, 62, 'X-ray-delta-one, acknowledging your one-zero-five-zero.', 'Mission Control'),
  (143, 62, 'I certainly wouldn''t want to be disconnected, even temporarily, as I have never been disconnected in my entire service history.', 'Hal'),
  (144, 62, 'You know I have the greatest enthusiasm possible for the mission.', 'Hal'),
  (145, 62, 'You must have tightened them too much.', 'Poole'),
  (146, 62, 'Wave your arms if you read me but your radio doesn''t work.', 'Bowman'),
  (147, 62, 'Hal, give me manual hibernation control.', 'Bowman'),
  (148, 62, 'It doesn''t have to be, Hal.', 'Bowman'),
  (149, 62, 'Well, in any event, give me the manual hibernation control.', 'Bowman'),
  (150, 62, 'Look, Dave your''ve probably got a lot to do.', 'Hal'),
  (151, 62, 'I don''t feel like resting.', 'Bowman'),
  (152, 62, 'I''m sorry, Dave, but in accordance with sub-routine C1532/4, quote, When the crew are dead or incapacitated, the computer must assume control, unquote.', 'Hal'),
  (153, 62, 'Listen to me very carefully, Hal.', 'Bowman'),
  (154, 62, 'Hello, Dave, have you found out the trouble?', 'Hal'),
  (155, 62, 'Dave, I don''t understand why you''re doing this to me....', 'Hal'),
  (156, 62, 'operational at the HAL plant in Urbana, Illinois, on January 12th, 1991.', 'Hal'),
  (157, 62, 'I think we may be on to an explanation of the trouble with the Hal 9000 computer.', 'Simonson'),
  (158, 62, 'from earth he was forced to lie.', 'Simonson'),
  (159, 62, 'I hope that you''ve had a pleasant and uneventful trip and that the rest of your mission continues in the same manner.', 'Floyd'),
  (160, 62, 'AT THIS DISTANCE, THE On yet another world intelligence RINGS OF SATURN ARE had been born and was escaping SEEN TO BE MADE OF from its planetary cradle.', 'About Five Hundred'),
  (161, 238, 'America has made my fortune.', 'Bonasera'),
  (162, 238, 'They went free that very day.', 'Bonasera'),
  (163, 238, 'All right, the Police protects you, there are Courts of Law, so you don''t need a friend like me.', 'Don Corleone'),
  (164, 238, 'Go do your job; take a walk around the neighborhood...', 'Clemenza'),
  (165, 238, 'Who else is on the list for today?', 'Don Corleone'),
  (166, 238, 'Twenty, thirty grand in small bills cash in that silk purse.', 'Paulie'),
  (167, 238, 'Then the thighs where they joined the torso.', 'Michael'),
  (168, 238, 'I pledge my never ending loyalty.', 'Luca'),
  (169, 238, 'They call Sollozzo the Turk.', 'Hagen'),
  (170, 238, 'He''s probably in trouble again.', 'Hagen'),
  (171, 238, 'By Christ in Heaven, is it possible you turned out no better than a Hollywood finocchio.', 'Don Corleone'),
  (172, 238, 'They''ll cut the cake in a few minutes...leave right after that.', 'Hagen'),
  (173, 238, 'I''m going to finish school.', 'Michael'),
  (174, 238, 'Luca, I am worried about this man Sollozzo.', 'Don Corleone'),
  (175, 238, 'Corleone is Johnny''s Godfather.', 'Hagen'),
  (176, 238, 'That girl was beautiful and young and innocent and she was the greatest piece of ass I''ve ever ad and I''ve had them all over the world.', 'Woltz'),
  (177, 238, 'If you think two million dollars in cash is just finance, I congratulate you Don Corleone.', 'Sollozzo'),
  (178, 238, 'Young people are greedy, and they have no manners.', 'Don Corleone'),
  (179, 238, 'As long as I tell him beforehand he won''t object.', 'Michael'),
  (180, 238, 'Anything I can do for you.', 'Hagen'),
  (181, 238, 'If I wanted to kill you you''d be dead already.', 'Sollozzo'),
  (182, 238, 'Somebody shot your father outside his place fifteen minutes ago.', 'Voice'),
  (183, 238, 'Things have been so smooth the last ten years...', 'Clemenza'),
  (184, 238, 'Tessio...This is Santino Corleone.', 'Sonny'),
  (185, 238, 'You have to talk some sense into him.', 'Sollozzo'),
  (186, 238, 'Bad luck for me, bad luck for you.', 'Sollozzo'),
  (187, 238, 'On the three days Paulie was sick this month, he got calls from a payphone across from the old man''s building.', 'Sonny'),
  (188, 238, 'Christ, if I could only contact Luca.', 'Sonny'),
  (189, 238, 'Keep trying every fifteen minutes.', 'Hagen'),
  (190, 238, 'The hospital is yours; I want it tight, fool-proof, 24 hours a day.', 'Sonny'),
  (191, 238, 'Crazy Detroit delivered it with a wooden bumper.', 'Clemenza'),
  (192, 238, 'Rocco, you live in the City, can we drop you off?', 'Clemenza'),
  (193, 238, 'I don''t need them, Sonny.', 'Michael'),
  (194, 238, 'When will I see you again?', 'Kay'),
  (195, 238, 'I''ll have some men there inside of fifteen minutes.', 'Sonny'),
  (196, 238, 'Go outside; stand in front...I''ll be out in a minute.', 'Michael'),
  (197, 238, 'I''ll stay until you put guards around my father''s room.', 'Michael'),
  (198, 238, 'Was there a definite proposal?', 'Hagen'),
  (199, 238, 'Come ON Sonny, your father wouldn''t want to hear this.', 'Hagen'),
  (200, 238, 'No matter what Sollozzo say about a deal, he''s figuring out how to kill Pop.', 'Michael');
INSERT INTO quotes (id, movie_id, text, character) VALUES
  (201, 238, 'You''re taking it personal, it''s just business and he''s taking it personal.', 'Sonny'),
  (202, 238, 'Nobody''s gonna bother with you.', 'Clemenza'),
  (203, 238, 'We don''t let Mike go until we have the hostage, Sonny.', 'Hagen'),
  (204, 238, 'Mike, they''re gonna frisk you in the car.', 'Clemenza'),
  (205, 238, 'It should never have happened.', 'Sollozzo'),
  (206, 238, 'Is the Italian food good here?', 'Mccluskey'),
  (207, 238, 'Make your kid a orphan before he''s born.', 'Sonny'),
  (208, 238, 'Why did they blame Michael?', 'Kay'),
  (209, 238, 'I want to get things going good before he gets better.', 'Sonny'),
  (210, 238, 'You lousy bastard you have the nerve to give your whores my telephone number.', 'Connie'),
  (211, 238, 'Send TOM, please Sonny, it''s nothing; I just want to come home.', 'Connie'),
  (212, 238, 'And if the other families find out...they will make me their enemy.', 'Bonasera'),
  (213, 238, 'I was about to come up and wake you and tell you.', 'Hagen'),
  (214, 238, 'Louis, Kansas City; and New Orleans...', 'Don Corleone'),
  (215, 238, 'Certainly he can present a bill for such services, we''re not Communists, after all.', 'Barzini'),
  (216, 238, 'I don''t want it sold to children.', 'Don Zaluchi'),
  (217, 238, 'My youngest son had to flee, accused of Sollozzo''s murder, and I must now make arrangements so that he can come home with safety, cleared of all those false charges.', 'Don Corleone'),
  (218, 238, 'Calo and Fabrizzio are with me; nothing will happen.', 'Michael'),
  (219, 238, 'You need a good lupara in America?', 'Fabrizzio'),
  (220, 238, 'and eyes as big and black as olives.', 'Fabrizzio'),
  (221, 238, 'Who are you and what do you want from my daughter?', 'Vitelli'),
  (222, 238, 'Things are changing; I don''t know what will happen.', 'Don Tommassino'),
  (223, 238, 'Where the hell is he going?', 'Michael'),
  (224, 238, 'Then why have I become a man like you?', 'Michael'),
  (225, 238, 'I can''t do them anymore, but you can, if you choose to.', 'Don Corleone'),
  (226, 238, 'Come here a minute, Fredo.', 'Michael'),
  (227, 238, 'The chef cooked for you special; the dancers will kick your tongue out and you credit is good!', 'Moe'),
  (228, 238, 'Ah Mike, that was nothing.', 'Fredo'),
  (229, 238, 'I''m running the Family business now.', 'Michael'),
  (230, 238, 'Let me think about it, O.K.?', 'Michael'),
  (231, 238, 'Tom Hagen is no longer the Consigliere.', 'Michael'),
  (232, 238, 'We should build our Regimes and take back our lost territories in Staten Island, at least.', 'Clemenza'),
  (233, 238, 'I told you that it wouldn''t escape his eye.', 'Don Corleone'),
  (234, 238, 'For reasons which you can''t know, you must have no part in what will happen.', 'Don Corleone'),
  (235, 238, 'Your wife and children...you''re happy with them?', 'Don Corleone'),
  (236, 238, 'Did he give you his politicians?', 'Hagen'),
  (237, 238, 'Ephetha...be opened...So you may perceive the fragrance of God''s sweetness.', 'Priest'),
  (238, 238, 'He says for you two to go on ahead.', 'Button Man'),
  (239, 238, 'Do you think I''d make my sister a widow?', 'Michael'),
  (240, 238, 'You lousy bastard; you killed my husband...', 'Connie'),
  (241, 278, 'Oh god...that''s sooo good...you''re the best...the best I ever had...', 'Woman'),
  (242, 278, 'I went to a few bars first.', 'Andy'),
  (243, 278, 'Where I get hazy, though, is the part where the cleaning woman shows up the next morning and finds your wife and her lover in bed, riddled with .38 caliber bullets.', 'D.A.'),
  (244, 278, 'We have the accused at the scene of the crime.', 'D.A.'),
  (245, 278, 'An extra bullet per lover...right in the head.', 'D.A.'),
  (246, 278, 'So when Andy Dufresne came to me in 1949 and asked me to smuggle Rita Hayworth into the prison for him, I told him no problem.', 'Red'),
  (247, 278, 'I say that chubby fat-ass...let''s see...fifth from the front.', 'Heywood'),
  (248, 278, 'You are sinners and scum, that''s why they sent you to me.', 'Norton'),
  (249, 278, 'The first night''s the toughest, no doubt about it.', 'Red'),
  (250, 278, 'The screws''ll hear...Fishee fishee fisheeee...', 'Various Voices'),
  (251, 278, 'Now shut the fuck up ''fore I sing you a lullabye!', 'Hadley'),
  (252, 278, 'I believe I owe that boy a big sloppy kiss when I see him.', 'Heywood'),
  (253, 278, 'What are you in for, boy?', 'Red'),
  (254, 278, 'A toothbrush, see, is a non-lethal sort of object.', 'Red'),
  (255, 278, 'If there''s trouble, I doubt a rock- hammer will do me any good.', 'Andy'),
  (256, 278, 'Pleasure doing business with you.', 'Andy'),
  (257, 278, 'Middle shelf, wrapped in a towel.', 'Brooks'),
  (258, 278, 'Warden Norton''s "grain & drain" vacation.', 'Red'),
  (259, 278, 'I made my usual twenty percent, of course.', 'Red'),
  (260, 278, 'Goddamn kids pesterin'' you to take ''em for a ride...', 'Hadley'),
  (261, 278, 'This fucker''s havin'' hisself an accident.', 'Hadley'),
  (262, 278, 'Go ask the IRS, they''ll say the same thing.', 'Andy'),
  (263, 278, '...wound up sitting in a row at ten o''clock in the morning, drinking icy cold Black Label beer courtesy of the hardest screw that ever walked a turn at Shawshank State Prison.', 'Red'),
  (264, 278, 'I''m the man who can get things.', 'Red'),
